mapper.update:
UPDATE t_sync_task
SET task_status = #{taskStatus},
    total_count = #{totalCount},
    insert_count = #{insertCount},
    update_count = #{updateCount},
    fail_count = #{failCount},
    summary_message = #{summaryMessage},
    finished_time = #{finishedTime}
WHERE task_id = #{taskId}
  AND user_id = #{userId}

mapper.select:
SELECT task.task_id, task.user_id, task.source_id, source.source_name, task.task_type, task.task_status, task.file_name, task.metric_category, task.total_count, task.insert_count, task.update_count, task.fail_count, task.summary_message, task.started_time, task.finished_time, task.created_time, task.last_change_time FROM t_sync_task task LEFT JOIN t_data_source source ON source.source_id = task.source_id WHERE task.user_id = #{userId}
AND task.source_id = #{sourceId}
ORDER BY task.started_time DESC, task.task_id DESC LIMIT #{limit}

SELECT COUNT(*)
FROM t_sync_task
WHERE user_id = #{userId}

mapper.delete:
DELETE FROM t_sync_task
WHERE source_id = #{sourceId}
  AND user_id = #{userId}
